(function(){
  var LS='vf_lang';
  function pick(){
    var s=localStorage.getItem(LS); if(s && window.VF_I18N[s]) return s;
    var codes=window.VF_LANGS.map(function(l){return l.code;});
    var langs=(navigator.languages||[navigator.language||'en']);
    for(var i=0;i<langs.length;i++){ var c=(langs[i]||'').slice(0,2).toLowerCase(); if(codes.indexOf(c)>=0) return c; }
    return 'en';
  }
  function apply(lang){
    var t=window.VF_I18N[lang]||window.VF_I18N.en;
    document.documentElement.setAttribute('lang',lang);
    document.querySelectorAll('[data-i18n]').forEach(function(el){
      var k=el.getAttribute('data-i18n'); if(t[k]!=null) el.textContent=t[k];
    });
    document.querySelectorAll('[data-i18n-html]').forEach(function(el){
      var k=el.getAttribute('data-i18n-html'); if(t[k]!=null) el.innerHTML=t[k];
    });
    localStorage.setItem(LS,lang);
    var sel=document.getElementById('vfLang'); if(sel) sel.value=lang;
    window.vfLang=lang;
    if(typeof window.vfAfterApply==='function'){ try{ window.vfAfterApply(lang); }catch(e){} }
  }
  window.vfT=function(k){ var t=window.VF_I18N[window.vfLang||'en']||window.VF_I18N.en; return t[k]; };
  window.vfSetLang=function(l){ apply(l); };
  document.addEventListener('DOMContentLoaded',function(){
    var sel=document.getElementById('vfLang');
    if(sel){ sel.addEventListener('change',function(){ apply(sel.value); }); }
    apply(pick());
  });
})();
